mapper.select:
SELECT title 
FROM Review 
WHERE review_no = #{targetId}

mapper.update:
UPDATE Review 
SET view_cnt = view_cnt + 1 
WHERE review_no = #{reviewNo}

mapper.insert:
INSERT INTO Review ( user_id, company_no, product_no, title, content, rating, is_paid, original_name, stored_name, img_url, receipt_name, booking_source, reg_date, approval_status, view_cnt, total_cost, external_name, thumbnail_url
) VALUES ( #{userId}, #{companyNo}, #{productNo}, #{title}, #{content}, #{rating}, #{isPaid}, #{originalName}, #{storedName}, #{imgUrl}, #{receiptName}, #{bookingSource}, NOW(), 'WAIT', 0, #{totalCost}, #{externalName}, #{thumbnailUrl}
)

mapper.select:
SELECT COUNT(*) 
FROM Pass_Usage_Log 
WHERE user_id = #{userId} AND review_no = #{reviewNo}

SELECT IFNULL(remaining_count, 0)
FROM User_Pass_Wallet 
WHERE user_id = #{userId}

SELECT COUNT(*) 
FROM free_view_log 
WHERE user_id = #{userId} AND review_no = #{reviewNo}

SELECT user_id AS userId, is_paid AS isPaid, like_cnt AS likeCnt
FROM review
WHERE review_no = #{value}
